-- ============================================================
-- 01_staging.sql  —  legacy dump loaded as staging tables (run FIRST)
-- Paste into the Neon SQL Editor and Run.
-- Creates public."User", "DiscountCode", "Order", etc. (PascalCase),
-- which do NOT collide with the snake_case app tables.
-- Undefined legacy enum types (Role/PayoutStatus) are stored as text.
-- ============================================================
BEGIN;

DROP TABLE IF EXISTS public."User" CASCADE;
CREATE TABLE public."User" (
    id text NOT NULL,
    email text NOT NULL,
    "passwordHash" text NOT NULL,
    name text NOT NULL,
    role text DEFAULT 'AFFILIATE'::text NOT NULL,
    "defaultCommissionRate" double precision DEFAULT 0.20 NOT NULL,
    active boolean DEFAULT true NOT NULL,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL,
    "passwordPlain" text
);

DROP TABLE IF EXISTS public."DiscountCode" CASCADE;
CREATE TABLE public."DiscountCode" (
    id text NOT NULL,
    code text NOT NULL,
    "affiliateId" text NOT NULL,
    "discountPercent" double precision DEFAULT 0.10 NOT NULL,
    "commissionRateOverride" double precision,
    label text,
    active boolean DEFAULT true NOT NULL,
    "expiresAt" timestamp(3) without time zone,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL
);

DROP TABLE IF EXISTS public."CommissionSplit" CASCADE;
CREATE TABLE public."CommissionSplit" (
    id text NOT NULL,
    "discountCodeId" text NOT NULL,
    "recipientUserId" text NOT NULL,
    "sharePercent" double precision NOT NULL,
    note text,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL
);

DROP TABLE IF EXISTS public."Payout" CASCADE;
CREATE TABLE public."Payout" (
    id text NOT NULL,
    "affiliateId" text NOT NULL,
    amount double precision NOT NULL,
    period text NOT NULL,
    status text DEFAULT 'PENDING'::text NOT NULL,
    notes text,
    "paidAt" timestamp(3) without time zone,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "updatedAt" timestamp(3) without time zone NOT NULL,
    "periodEnd" timestamp(3) without time zone,
    "periodStart" timestamp(3) without time zone
);

DROP TABLE IF EXISTS public."Order" CASCADE;
CREATE TABLE public."Order" (
    id text NOT NULL,
    "externalOrderId" text,
    "discountCodeId" text,
    "customerFirstName" text NOT NULL,
    "itemsSummary" text NOT NULL,
    "orderTotal" double precision NOT NULL,
    "commissionEarned" double precision DEFAULT 0 NOT NULL,
    attributed boolean DEFAULT false NOT NULL,
    source text DEFAULT 'shopify'::text NOT NULL,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    currency text DEFAULT 'USD'::text NOT NULL,
    "storeName" text,
    "customerLastName" text
);

DROP TABLE IF EXISTS public."OrderCommission" CASCADE;
CREATE TABLE public."OrderCommission" (
    id text NOT NULL,
    "orderId" text NOT NULL,
    "recipientUserId" text NOT NULL,
    amount double precision NOT NULL,
    "sharePercent" double precision DEFAULT 1.0 NOT NULL,
    "createdAt" timestamp(3) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    "payoutId" text
);

COMMIT;
